<?php
namespace App\Models;use App\Models\Concerns\BelongsToWorkspace;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\SoftDeletes;class Project extends Model{use BelongsToWorkspace,SoftDeletes;public const STATUSES=['active','hold','completed','archived'];protected $fillable=['workspace_id','name','code','description','client_name','project_manager_id','status','start_date','end_date'];protected function casts():array{return['start_date'=>'date','end_date'=>'date'];}public function manager(){return $this->belongsTo(User::class,'project_manager_id');}public function tasks(){return $this->hasMany(Task::class);}}
